const GEN_BANNERS: Banner[] = [];
TEMPLATES.forEach((tmpl, ti) => {
  PAL_KEYS.forEach((pk, pi) => {
    const pal = PALETTES[pk];
    GEN_BANNERS.push({
      id: `gen-${String(ti * PAL_KEYS.length + pi + 1).padStart(3, '0')}`,
      name: `${TEMPLATE_NAMES[ti]} · ${pk}`,
      style: `${CATEGORIES[ti]} · 800×200`,
      palette: pal.tag,
      svg: tmpl(pal, '{{NAME}}', '{{ROLE}}', '{{HANDLE}}'),
    });
  });
});

