export function fillBanner(svg: string, data: { name: string; role: string; handle: string }) {
  return svg
    .replace(/\{\{NAME\}\}/g, data.name || 'Your Name')
    .replace(/\{\{ROLE\}\}/g, data.role || 'Developer')
    .replace(/\{\{HANDLE\}\}/g, data.handle || 'username');
}

export const HERO_COUNT = HERO_BANNERS.length;
export const GEN_COUNT = GEN_BANNERS.length;
export const TOTAL_BANNERS = BANNERS.length;
export const PALETTE_NAMES = PAL_KEYS;
export const TEMPLATE_COUNT = TEMPLATES.length;
